<p>Actualités, conseils et informations sur la qualité électrique au Sénégal.</p>

<h2>Dernières Actualités</h2>
<p>Restez informé des dernières évolutions dans le domaine de l''électricité au Sénégal.</p>

<h2>Conseils Pratiques</h2>
<p>Des conseils d''experts pour améliorer la qualité et la sécurité de vos installations électriques.</p>

<h2>Normes et Réglementation</h2>
<p>Tout savoir sur les normes électriques applicables et les évolutions réglementaires.</p>', NULL, NULL, 'index,follow', NULL, 'default', true, true, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, NULL, 0, NULL, '[]', '[]', NULL, 2, '2026-01-22T04:34:32.874796+00:00', '2026-01-22T04:34:32.874796+00:00', 'draft', NULL, NULL, 1, true, 'fr', '{}', 0, 0, 0, NULL, false, NULL, 1, '{}', '{}', '[]', NULL, '{}', 3600, false, NULL, NULL, NULL, '[]', 'public', '[]', NULL, '[]', 0, 0, 0, '{}', '{}', '{}', 0, '{}', NULL, NULL, '{}', '{}', NULL, NULL, false, false, 0, 0, '{"layout":"default","body_font":"sans-serif","custom_css":"","text_color":"#333333","hero_height":"medium","accent_color":"#0066cc","heading_font":"sans-serif","hero_enabled":true,"hero_overlay":0.3,"content_width":"default","hero_alignment":"center","custom_sections":[],"sidebar_enabled":false,"background_color":"#ffffff","sidebar_position":"right","footer_cta_enabled":true}', 'standard', '{"og_image":"","og_title":"","schema_type":"WebPage","twitter_card":"summary","canonical_url":"","focus_keyword":"","og_description":"","meta_description":""}', false, NULL, 'closed', NULL, '[]', '[]', NULL, 1, NULL, NULL, NULL, 'html', 'code', 'raw', '{}', false, false) ON CONFLICT DO NOTHING;
INSERT INTO pages (id, title, slug, content, meta_description, meta_keywords, meta_robots, featured_image, template, show_hero, show_footer, custom_css, custom_js, header_html, footer_html, hero_title, hero_subtitle, hero_background_image, hero_cta_text, hero_cta_link, is_published, publish_date, unpublish_date, menu_order, parent_id, categories, tags, author, reading_time, created_at, updated_at, workflow_status, approved_by, approved_at, version_number, is_latest_version, language_code, translations, view_count, unique_views, conversion_rate, last_viewed_at, is_ab_test_variant, ab_test_group, ab_test_weight, publish_schedule, unpublish_schedule, webhook_urls, external_id, api_metadata, cache_ttl, is_cached, last_cached_at, created_by, updated_by, revision_history, security_level, media_gallery, featured_video, attachments, engagement_score, seo_score, performance_score, custom_fields, custom_settings, geo_targeting, accessibility_score, alt_texts, reserved_field_1, reserved_field_2, reserved_field_3, reserved_field_4, reserved_timestamp_1, reserved_timestamp_2, reserved_boolean_1, reserved_boolean_2, reserved_integer_1, reserved_integer_2, design_options, layout_type, seo_options, is_sticky, excerpt, comment_status, published_at, content_blocks, plugins_active, translation_of, version, content_raw, content_compiled, content_hash, content_type, editor_engine, render_engine, content_contract, locked, immutable) VALUES ('764bf968-dcdc-4d6c-9e94-0121f441ad63', 'Formations PROQUELEC', 'formations-proquelec', '<div class="space-y-8">
<section class="bg-gradient-to-r from-proqblue to-blue-600 text-white rounded-lg p-8 mb-8">
  <h2 class="text-3xl font-bold mb-3">Formations PROQUELEC</h2>
  <p class="text-xl">Développez vos compétences avec nos programmes de formation professionnels</p>
</section>

<section class="space-y-4">
  <h3 class="text-2xl font-bold text-gray-900">Nos Programmes de Formation</h3>
  <p class="text-gray-700">PROQUELEC propose une gamme complète de formations pour les professionnels du secteur électrique.</p>
</section>

<section class="grid md:grid-cols-2 gap-6">
  <div class="border border-gray-200 rounded-lg p-6 hover:shadow-lg transition">
    <h4 class="text-xl font-bold text-proqblue mb-3">Formation Initiale</h4>
    <p class="text-gray-700 mb-4">Formation complète pour les nouveaux professionnels couvrant les bases de l''électricité et la sécurité.</p>
    <ul class="space-y-2 text-sm text-gray-600">
      <li>✓ Durée: 4-6 semaines</li>
      <li>✓ Niveau: Débutant</li>
      <li>✓ Certification incluse</li>
    </ul>
  </div>

  <div class="border border-gray-200 rounded-lg p-6 hover:shadow-lg transition">
    <h4 class="text-xl font-bold text-proqblue mb-3">Formation Continue</h4>
    <p class="text-gray-700 mb-4">Mises à jour régulières sur les nouvelles normes et technologies électriques.</p>
    <ul class="space-y-2 text-sm text-gray-600">
      <li>✓ Durée: 1-2 semaines</li>
      <li>✓ Niveau: Professionnel</li>
      <li>✓ Points de formation</li>
    </ul>
  </div>

  <div class="border border-gray-200 rounded-lg p-6 hover:shadow-lg transition">
    <h4 class="text-xl font-bold text-proqblue mb-3">Spécialisation</h4>
    <p class="text-gray-700 mb-4">Formation spécialisée dans des domaines comme l''énergie renouvelable et les systèmes avancés.</p>
    <ul class="space-y-2 text-sm text-gray-600">
      <li>✓ Durée: 2-3 semaines</li>
      <li>✓ Niveau: Avancé</li>
      <li>✓ Expertise reconnue</li>
    </ul>
  </div>

  <div class="border border-gray-200 rounded-lg p-6 hover:shadow-lg transition">
    <h4 class="text-xl font-bold text-proqblue mb-3">Séminaires</h4>
    <p class="text-gray-700 mb-4">Sessions courtes sur des sujets spécifiques et tendances du secteur.</p>
    <ul class="space-y-2 text-sm text-gray-600">
      <li>✓ Durée: 1 jour</li>
      <li>✓ Flexible</li>
      <li>✓ Attestation</li>
    </ul>
  </div>
</section>

<section class="space-y-4 mt-8">
  <h3 class="text-2xl font-bold text-gray-900">Modalités de Formation</h3>
  <div class="space-y-3">
    <div class="flex gap-4">
      <span class="text-proqblue font-bold text-xl">🏫</span>
      <div>
        <h4 class="font-bold text-gray-900">Présentiel</h4>
        <p class="text-gray-700">Formation directe dans nos centres accrédités avec matériel moderne.</p>
      </div>
    </div>
    <div class="flex gap-4">
      <span class="text-proqblue font-bold text-xl">💻</span>
      <div>
        <h4 class="font-bold text-gray-900">Hybride</h4>
        <p class="text-gray-700">Combinaison de modules en ligne et sessions pratiques en présence.</p>
      </div>
    </div>
    <div class="flex gap-4">
      <span class="text-proqblue font-bold text-xl">🌐</span>
      <div>
        <h4 class="font-bold text-gray-900">En Ligne</h4>
        <p class="text-gray-700">Modules 100% numériques avec plateforme interactive et support tuteur.</p>
      </div>
    </div>
  </div>
</section>

<section class="space-y-4 mt-8 bg-gray-50 rounded-lg p-6">
  <h3 class="text-2xl font-bold text-gray-900">Inscription et Information</h3>
  <p class="text-gray-700 mb-4">Contactez notre équipe de formation pour connaître les prochaines sessions.</p>
  <div class="space-y-2">
    <p class="text-gray-700"><strong>Email:</strong> formations@proquelec.sn</p>
    <p class="text-gray-700"><strong>Tél:</strong> +221 33 123 45 67 (poste formation)</p>
  </div>
</section>
</div>', NULL, NULL, 'index,follow', NULL, 'default', true, true, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, NULL, 0, NULL, '[]', '[]', NULL, 8, '2026-01-22T04:49:24.631533+00:00', '2026-01-22T04:49:24.631533+00:00', 'draft', NULL, NULL, 1, true, 'fr', '{}', 0, 0, 0, NULL, false, NULL, 1, '{}', '{}', '[]', NULL, '{}', 3600, false, NULL, NULL, NULL, '[]', 'public', '[]', NULL, '[]', 0, 0, 0, '{}', '{}', '{}', 0, '{}', NULL, NULL, '{}', '{}', NULL, NULL, false, false, 0, 0, '{"layout":"default","body_font":"sans-serif","custom_css":"","text_color":"#333333","hero_height":"medium","accent_color":"#0066cc","heading_font":"sans-serif","hero_enabled":true,"hero_overlay":0.3,"content_width":"default","hero_alignment":"center","custom_sections":[],"sidebar_enabled":false,"background_color":"#ffffff","sidebar_position":"right","footer_cta_enabled":true}', 'standard', '{"og_image":"","og_title":"","schema_type":"WebPage","twitter_card":"summary","canonical_url":"","focus_keyword":"","og_description":"","meta_description":""}', false, NULL, 'closed', NULL, '[]', '[]', NULL, 1, NULL, NULL, NULL, 'html', 'code', 'raw', '{}', false, false) ON CONFLICT DO NOTHING;
