INSERT INTO pages (id, title, slug, content, meta_description, meta_keywords, meta_robots, featured_image, template, show_hero, show_footer, custom_css, custom_js, header_html, footer_html, hero_title, hero_subtitle, hero_background_image, hero_cta_text, hero_cta_link, is_published, publish_date, unpublish_date, menu_order, parent_id, categories, tags, author, reading_time, created_at, updated_at, workflow_status, approved_by, approved_at, version_number, is_latest_version, language_code, translations, view_count, unique_views, conversion_rate, last_viewed_at, is_ab_test_variant, ab_test_group, ab_test_weight, publish_schedule, unpublish_schedule, webhook_urls, external_id, api_metadata, cache_ttl, is_cached, last_cached_at, created_by, updated_by, revision_history, security_level, media_gallery, featured_video, attachments, engagement_score, seo_score, performance_score, custom_fields, custom_settings, geo_targeting, accessibility_score, alt_texts, reserved_field_1, reserved_field_2, reserved_field_3, reserved_field_4, reserved_timestamp_1, reserved_timestamp_2, reserved_boolean_1, reserved_boolean_2, reserved_integer_1, reserved_integer_2, design_options, layout_type, seo_options, is_sticky, excerpt, comment_status, published_at, content_blocks, plugins_active, translation_of, version, content_raw, content_compiled, content_hash, content_type, editor_engine, render_engine, content_contract, locked, immutable) VALUES ('e5fcad66-3bff-471a-82ec-eb98587060bc', 'Expertises & Solutions', 'expertises-techniques', '<div class="space-y-12">
