    <a href="/outils" class="text-blue-600 font-bold hover:underline">Accéder à notre Base de Données Technique &rarr;</a>
  </div>
</div>', 'Découvrez l''expertise technique de PROQUELEC : Audit, Conseil, Solutions Électriques et Base de Données Matériaux.', '', 'index,follow', '', 'full-width', true, true, '', '', '', '', '', '', '', '', '', true, NULL, NULL, 10, NULL, '[]', '[]', '', 1, '2026-01-22T23:16:40.333547+00:00', '2026-01-23T05:17:13.176111+00:00', 'approved', NULL, NULL, 1, true, 'fr', '{}', 0, 0, 0, NULL, false, NULL, 1, '{}', '{}', '[]', NULL, '{}', 3600, false, NULL, NULL, NULL, '[]', 'public', '[]', NULL, '[]', 0, 0, 0, '{}', '{}', '{}', 0, '{}', NULL, NULL, '{}', '{}', NULL, NULL, false, false, 0, 0, '{"layout":"default","body_font":"sans-serif","custom_css":"","text_color":"#333333","hero_height":"medium","accent_color":"#0066cc","heading_font":"sans-serif","hero_enabled":true,"hero_overlay":0.3,"content_width":"default","hero_alignment":"center","custom_sections":[],"sidebar_enabled":false,"background_color":"#ffffff","sidebar_position":"right","footer_cta_enabled":true}', 'standard', '{"og_image":"","og_title":"","schema_type":"WebPage","twitter_card":"summary","canonical_url":"","focus_keyword":"","og_description":"","meta_description":""}', false, '', 'closed', NULL, '[]', '[]', NULL, 1, '<div class="space-y-12">
