INSERT INTO normative_articles (id, book_id, chapter_ref, article_ref, content_exact, safety_objective, application_conditions, prohibitions, formulas, safety_thresholds, is_premium, keywords, created_at) VALUES ('789d71b5-3499-4665-9936-78cd6a23c03f', '92ed1366-179b-4efc-be91-464ee666af0f', 'Titre 5 / Partie 5-52', 'Art 521.1', 'Les prescriptions de la présente partie s''appliquent au choix et à la mise en œuvre des canalisations électriques, y compris les conducteurs et câbles, dans les installations électriques.', 'Définir le cadre d''application des règles de canalisations.', 'Toutes installations électriques BT.', NULL, NULL, '{}', false, NULL, '2026-01-24T06:38:58.854158+00:00') ON CONFLICT DO NOTHING;
INSERT INTO normative_articles (id, book_id, chapter_ref, article_ref, content_exact, safety_objective, application_conditions, prohibitions, formulas, safety_thresholds, is_premium, keywords, created_at) VALUES ('02512851-7cbe-40e8-9240-b7443edcb951', '92ed1366-179b-4efc-be91-464ee666af0f', 'Titre 5 / Partie 5-52', 'Art 523.1', 'Les courants admissibles dans les conducteurs et câbles doivent être déterminés conformément aux tableaux de courants admissibles en fonction de la section des conducteurs, du mode de pose, du nombre de conducteurs chargés et de la température ambiante. Des facteurs de correction doivent être appliqués selon les conditions d''installation.', 'Éviter l''échauffement excessif des conducteurs.', 'Tous types de canalisations.', NULL, NULL, '{}', false, NULL, '2026-01-24T06:38:58.854158+00:00') ON CONFLICT DO NOTHING;
INSERT INTO normative_articles (id, book_id, chapter_ref, article_ref, content_exact, safety_objective, application_conditions, prohibitions, formulas, safety_thresholds, is_premium, keywords, created_at) VALUES ('7d03253c-e986-4387-84bd-bc5257d21ec8', '92ed1366-179b-4efc-be91-464ee666af0f', 'Titre 5 / Partie 5-52', 'Art 524.1', 'La section des conducteurs doit être déterminée en fonction du courant d''emploi, de la chute de tension admissible et des contraintes mécaniques. La section minimale des conducteurs de phase doit être de 1,5 mm² pour les circuits d''éclairage et de 2,5 mm² pour les circuits de prises de courant.', 'Garantir la tenue mécanique et électrique des conducteurs.', 'Installations domestiques et tertiaires.', NULL, NULL, '{}', false, NULL, '2026-01-24T06:38:58.854158+00:00') ON CONFLICT DO NOTHING;
INSERT INTO normative_articles (id, book_id, chapter_ref, article_ref, content_exact, safety_objective, application_conditions, prohibitions, formulas, safety_thresholds, is_premium, keywords, created_at) VALUES ('6fc02699-ce6e-442d-b7e7-48db4e417f9a', '92ed1366-179b-4efc-be91-464ee666af0f', 'Titre 5 / Partie 5-52', 'Art 525', 'La chute de tension entre l''origine de l''installation et tout point d''utilisation ne doit pas dépasser les valeurs suivantes : 3% pour les circuits d''éclairage, 5% pour les autres usages. Pour le calcul de la chute de tension, la formule suivante doit être utilisée : ΔU = (ρ × L × IB) / S pour les circuits monophasés, où ρ est la résistivité du conducteur, L la longueur du circuit, IB le courant d''emploi et S la section du conducteur.', 'Maintien de la performance des appareils électriques.', 'Toute installation BT.', NULL, '{"limits":{"other":0.05,"lighting":0.03},"monophase":"ΔU = (ρ × L × IB) / S","rho_copper":0.0225}', '{}', false, NULL, '2026-01-24T06:38:58.854158+00:00') ON CONFLICT DO NOTHING;
INSERT INTO normative_articles (id, book_id, chapter_ref, article_ref, content_exact, safety_objective, application_conditions, prohibitions, formulas, safety_thresholds, is_premium, keywords, created_at) VALUES ('9d60cb65-eacf-4970-8bde-fc0c174e0c8b', '92ed1366-179b-4efc-be91-464ee666af0f', 'Titre 5 / Partie 5-53', 'Art 530.1', 'Tout circuit doit être protégé contre les surintensités par un dispositif de protection à maximum de courant (disjoncteur ou fusible) dont les caractéristiques doivent être adaptées à la section des conducteurs et au courant d''emploi du circuit.', 'Protection des conducteurs et des personnes.', 'Tous les circuits.', NULL, NULL, '{}', false, NULL, '2026-01-24T06:38:58.854158+00:00') ON CONFLICT DO NOTHING;

