INSERT INTO blog_posts (id, author_id, category_id, title, content, published_at, created_at, excerpt, slug, cover_image_url) VALUES ('46646d84-6f1e-4385-9000-04819b7b017a', '4ad00493-e131-4b54-b0a9-92107b4f7bf0', 1, 'la plateforme Yoombal', '<p><strong>Découvrez la plateforme Yombale,</strong> l''outil incontournable pour tous vos projets en ligne ! Conçue pour allier performance et simplicité, cette plateforme vous permet de créer, gérer et optimiser votre présence digitale en quelques clics.&nbsp;</p><p><br></p><p>Avec Yombale, profitez d''une interface intuitive qui facilite la navigation, même pour les débutants. Ses fonctionnalités avancées incluent des modèles personnalisables, des outils de SEO intégrés et des options de marketing par courriel, vous permettant de maximiser votre visibilité et d''attirer de nouveaux clients.</p><p><br></p><p>La plateforme est également optimisée pour les appareils mobiles, garantissant que votre site est accessible partout et à tout moment. Ne manquez pas l''opportunité de donner vie à vos idées et de propulser votre projet vers de nouveaux sommets.&nbsp;</p><p><br></p><p>Rejoignez dès maintenant la communauté Yombale et transformez votre vision en réalité. Avec un essai gratuit de 30 jours, il n''y a jamais eu de meilleur moment pour vous lancer. Adoptez Yombale et observez votre succès grandir !</p>', '2025-06-15T21:39:46.057+00:00', '2025-06-15T21:43:43.767052+00:00', 'Découvrez la plateforme Yombale, l''outil incontournable pour tous vos projets en ligne ! Conçue pour allier performance et simplicité, cette plateforme vous permet de créer, gérer et optimiser votre présence digitale en quelques clics. ', 'yoombal', 'https://feddbe74-4209-488e-b5fd-64bc06de48f4.lovableproject.com/lovable-uploads/1decb48b-96c6-4e62-b4a2-a982c4cfa526.png') ON CONFLICT DO NOTHING;

